mapper.select:
SELECT COUNT(*) FROM STAGE_PREFER
WHERE MEMBER_NO =
#{memberNo}
AND STAGE_NO = #{stageNo}
AND PREFER_TYPE = #{preferType}

mapper.delete:
DELETE FROM STAGE_PREFER
WHERE MEMBER_NO = #{memberNo}
AND STAGE_NO = #{stageNo}
AND PREFER_TYPE = #{preferType}

DELETE FROM STAGE_PREFER
WHERE MEMBER_NO = #{memberNo}
AND STAGE_NO = #{stageNo}
AND PREFER_TYPE != #{preferType}

mapper.select:
SELECT COUNT(*) FROM STAGE_SAVE
WHERE MEMBER_NO =
#{memberNo}
AND STAGE_NO = #{stageNo}

mapper.delete:
DELETE FROM STAGE_SAVE
WHERE MEMBER_NO = #{memberNo}
AND STAGE_NO = #{stageNo}

mapper.select:
SELECT STAGE_NO AS stageNo, STAGE_TYPE AS stageType, STAGE_TITLE AS stageTitle, STAGE_THUMBNAIL AS stageThumbnail, STAGE_PERIOD AS stagePeriod, STAGE_PLACE AS stagePlace FROM STAGE_CACHE WHERE STAGE_TITLE LIKE '%' || #{query} || '%'
AND STAGE_TYPE = #{stageType}
ORDER BY CACHED_AT DESC FETCH FIRST 5 ROWS ONLY
